import{_ as c,M as t,p as l,q as u,N as n,R as a,t as s,V as o,a1 as p}from"./framework-188d6338.js";const d={},k=a("h1",{id:"fuse-js-vs-semantic-search",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#fuse-js-vs-semantic-search","aria-hidden":"true"},"#"),s(" Fuse.js vs Semantic Search")],-1),m=p(`<p>If you&#39;re building an AI-powered application, you&#39;ve probably considered embeddings and a service like Pinecone or Weaviate to power search. That&#39;s the right tool for some problems — but not all of them. Many search features that developers route through an embedding pipeline would be simpler, faster, and cheaper with client-side fuzzy search.</p><p>This guide helps you pick the right approach.</p><h2 id="the-core-difference" tabindex="-1"><a class="header-anchor" href="#the-core-difference" aria-hidden="true">#</a> The core difference</h2><p><strong>Fuse.js</strong> matches based on <em>characters</em> — it finds strings that look like what the user typed, tolerating typos, transpositions, and partial input.</p><p><strong>Semantic search</strong> matches based on <em>meaning</em> — it converts text into high-dimensional vectors using a language model, then finds items whose vectors are close together in that space.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>User types: &quot;recpie&quot;

Fuse.js:   &quot;recpie&quot; ≈ &quot;recipe&quot;         (character similarity)
Vector DB: &quot;recpie&quot; → [0.12, -0.84, …] (semantic embedding)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>These are fundamentally different operations, and they&#39;re good at different things. The architecture reflects that — Fuse.js runs entirely in the browser, while semantic search requires multiple network hops:</p>`,7),h=p(`<h2 id="when-to-use-fuse-js" tabindex="-1"><a class="header-anchor" href="#when-to-use-fuse-js" aria-hidden="true">#</a> When to use Fuse.js</h2><p>Use Fuse.js when the user is <strong>typing to find something they already know exists</strong> — a name, a title, a setting, a command. This is the most common search interaction in applications.</p><p><strong>Good fits:</strong></p><ul><li>Searching a list of contacts, products, files, or settings</li><li>Command palettes and autocomplete</li><li>Filtering a table or dropdown by name</li><li>Any dataset under ~100k items that lives in the browser</li><li>Offline or privacy-sensitive contexts where data shouldn&#39;t leave the device</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">import</span> Fuse <span class="token keyword">from</span> <span class="token string">&#39;fuse.js&#39;</span>

<span class="token keyword">const</span> products <span class="token operator">=</span> <span class="token punctuation">[</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;MacBook Pro 16&quot;&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">sku</span><span class="token operator">:</span> <span class="token string">&#39;MBP16&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">category</span><span class="token operator">:</span> <span class="token string">&#39;Laptops&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;Magic Keyboard&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">sku</span><span class="token operator">:</span> <span class="token string">&#39;MK&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">category</span><span class="token operator">:</span> <span class="token string">&#39;Accessories&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;Mac Mini M4&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">sku</span><span class="token operator">:</span> <span class="token string">&#39;MM4&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">category</span><span class="token operator">:</span> <span class="token string">&#39;Desktops&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token comment">// ... hundreds or thousands of items</span>
<span class="token punctuation">]</span>

<span class="token keyword">const</span> fuse <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Fuse</span><span class="token punctuation">(</span>products<span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">keys</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;name&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;sku&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;category&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token literal-property property">threshold</span><span class="token operator">:</span> <span class="token number">0.4</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token comment">// Typo-tolerant, instant, runs in the browser</span>
fuse<span class="token punctuation">.</span><span class="token function">search</span><span class="token punctuation">(</span><span class="token string">&#39;mackbook&#39;</span><span class="token punctuation">)</span>
<span class="token comment">// [{ item: { name: &#39;MacBook Pro 16&quot;&#39;, ... }, ... }]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Key advantages:</strong></p><ul><li><strong>Zero latency</strong> — no network round-trip, no API call</li><li><strong>Zero cost</strong> — no embedding model, no vector database, no per-query fees</li><li><strong>Zero dependencies</strong> — works offline, no backend required</li><li><strong>Privacy</strong> — data never leaves the user&#39;s device</li><li><strong>Tiny footprint</strong> — ~5KB gzipped, no SDK or HTTP client needed</li><li><strong>Simplicity</strong> — <code>npm install fuse.js</code>, write 5 lines of code, done</li></ul><h2 id="when-to-use-semantic-search" tabindex="-1"><a class="header-anchor" href="#when-to-use-semantic-search" aria-hidden="true">#</a> When to use semantic search</h2><p>Use semantic search when the user is <strong>describing what they want in natural language</strong> and the answer requires understanding meaning, not matching characters.</p><p><strong>Good fits:</strong></p><ul><li>&quot;Find articles about climate change&quot; (even if they don&#39;t contain those words)</li><li>Semantic document retrieval for RAG pipelines</li><li>Finding similar images, products, or recommendations</li><li>Cross-language search</li><li>Large corpora (millions of documents) where meaning matters more than exact text</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// Pseudocode — requires an embedding model + vector database</span>
<span class="token keyword">const</span> embedding <span class="token operator">=</span> <span class="token keyword">await</span> openai<span class="token punctuation">.</span>embeddings<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">model</span><span class="token operator">:</span> <span class="token string">&#39;text-embedding-3-small&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">input</span><span class="token operator">:</span> <span class="token string">&#39;lightweight search library&#39;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token keyword">const</span> results <span class="token operator">=</span> <span class="token keyword">await</span> vectorDB<span class="token punctuation">.</span><span class="token function">query</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">vector</span><span class="token operator">:</span> embedding<span class="token punctuation">.</span>data<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">.</span>embedding<span class="token punctuation">,</span>
  <span class="token literal-property property">topK</span><span class="token operator">:</span> <span class="token number">5</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Key costs:</strong></p><ul><li>Embedding model API calls (~$0.02 per 1M tokens, but it adds up)</li><li>Vector database hosting ($20–500+/month)</li><li>Indexing pipeline complexity</li><li>Latency from network round-trips (50–500ms per query)</li><li>Cold-start issues in serverless setups</li></ul><h2 id="side-by-side-comparison" tabindex="-1"><a class="header-anchor" href="#side-by-side-comparison" aria-hidden="true">#</a> Side-by-side comparison</h2><table><thead><tr><th></th><th>Fuse.js</th><th>Semantic search</th></tr></thead><tbody><tr><td><strong>Matching</strong></td><td>Character similarity (fuzzy)</td><td>Semantic similarity (meaning)</td></tr><tr><td><strong>Runs on</strong></td><td>Client (browser/Node)</td><td>Server (API + database)</td></tr><tr><td><strong>Latency</strong></td><td>&lt; 10ms</td><td>50–500ms</td></tr><tr><td><strong>Cost</strong></td><td>Free</td><td>Embedding API + DB hosting</td></tr><tr><td><strong>Setup</strong></td><td><code>npm install fuse.js</code></td><td>Model + DB + indexing pipeline</td></tr><tr><td><strong>Handles typos</strong></td><td>Yes (core feature)</td><td>Poorly (embeddings are spelling-sensitive)</td></tr><tr><td><strong>Understands meaning</strong></td><td>No</td><td>Yes</td></tr><tr><td><strong>Offline</strong></td><td>Yes</td><td>No</td></tr><tr><td><strong>Dataset size</strong></td><td>Thousands to ~100k</td><td>Millions+</td></tr><tr><td><strong>Dependencies</strong></td><td>Zero</td><td>Embedding model, vector DB, backend</td></tr></tbody></table><h2 id="common-mistake-using-embeddings-for-simple-lookup" tabindex="-1"><a class="header-anchor" href="#common-mistake-using-embeddings-for-simple-lookup" aria-hidden="true">#</a> Common mistake: using embeddings for simple lookup</h2><p>A pattern I see frequently in AI applications:</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// Over-engineered: calling an API to search 200 items</span>
<span class="token keyword">const</span> response <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;/api/search&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">method</span><span class="token operator">:</span> <span class="token string">&#39;POST&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">body</span><span class="token operator">:</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">query</span><span class="token operator">:</span> userInput <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// Server: embeds query → queries Pinecone → returns results</span>
<span class="token comment">// Total time: 300ms, cost: ~$0.001 per query</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>When all you needed was:</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// Simple: search 200 items in the browser in &lt;1ms</span>
<span class="token keyword">const</span> fuse <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Fuse</span><span class="token punctuation">(</span>items<span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">keys</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;name&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;description&#39;</span><span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> results <span class="token operator">=</span> fuse<span class="token punctuation">.</span><span class="token function">search</span><span class="token punctuation">(</span>userInput<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ask yourself: <em>Is the user searching by meaning, or searching by name?</em> If the answer is &quot;by name&quot; (or by title, SKU, email, filename, etc.), you probably don&#39;t need embeddings.</p><h2 id="using-both-together" tabindex="-1"><a class="header-anchor" href="#using-both-together" aria-hidden="true">#</a> Using both together</h2><p>The best AI applications often use both. Fuse.js handles the fast, interactive search layer while semantic search handles the semantic layer.</p><p><strong>Example: a documentation chatbot</strong></p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">import</span> Fuse <span class="token keyword">from</span> <span class="token string">&#39;fuse.js&#39;</span>

<span class="token comment">// Layer 1: Instant search-as-you-type for known pages</span>
<span class="token keyword">const</span> fuse <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Fuse</span><span class="token punctuation">(</span>docs<span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">keys</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;title&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;headings&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;slug&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token literal-property property">threshold</span><span class="token operator">:</span> <span class="token number">0.3</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token keyword">function</span> <span class="token function">handleSearchInput</span><span class="token punctuation">(</span><span class="token parameter">query</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// Fast fuzzy search — instant results as the user types</span>
  <span class="token keyword">return</span> fuse<span class="token punctuation">.</span><span class="token function">search</span><span class="token punctuation">(</span>query<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">slice</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token comment">// Layer 2: Semantic search when the user asks a question</span>
<span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">handleQuestion</span><span class="token punctuation">(</span><span class="token parameter">question</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> embedding <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">embed</span><span class="token punctuation">(</span>question<span class="token punctuation">)</span>
  <span class="token keyword">const</span> chunks <span class="token operator">=</span> <span class="token keyword">await</span> vectorDB<span class="token punctuation">.</span><span class="token function">query</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">vector</span><span class="token operator">:</span> embedding<span class="token punctuation">,</span> <span class="token literal-property property">topK</span><span class="token operator">:</span> <span class="token number">10</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token keyword">return</span> <span class="token keyword">await</span> llm<span class="token punctuation">.</span><span class="token function">answer</span><span class="token punctuation">(</span>question<span class="token punctuation">,</span> chunks<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Example: an e-commerce app</strong></p><ul><li><strong>Product search bar</strong> — Fuse.js for instant, typo-tolerant filtering</li><li><strong>&quot;Find similar products&quot;</strong> — Semantic search for recommendations</li><li><strong>Category browsing with filter</strong> — Fuse.js for filtering within a category</li><li><strong>Natural language queries</strong> (&quot;warm jacket under $100&quot;) — Semantic search</li></ul><h2 id="decision-checklist" tabindex="-1"><a class="header-anchor" href="#decision-checklist" aria-hidden="true">#</a> Decision checklist</h2><p>Choose <strong>Fuse.js</strong> when:</p><ul><li>[ ] The dataset fits in memory (under ~100k items)</li><li>[ ] Users search by typing names, titles, or known terms</li><li>[ ] You need instant (&lt; 10ms) results</li><li>[ ] You want zero infrastructure cost</li><li>[ ] The app needs to work offline</li><li>[ ] Typo tolerance matters more than semantic understanding</li></ul><p>Choose <strong>semantic search</strong> when:</p><ul><li>[ ] Users describe what they want in natural language</li><li>[ ] You need to find semantically similar content</li><li>[ ] The dataset is too large for client-side search</li><li>[ ] You&#39;re building a RAG pipeline for an LLM</li><li>[ ] Cross-language search is a requirement</li></ul><h2 id="getting-started" tabindex="-1"><a class="header-anchor" href="#getting-started" aria-hidden="true">#</a> Getting started</h2><p>If Fuse.js is the right fit, you can be up and running in under a minute:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span> fuse.js
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">import</span> Fuse <span class="token keyword">from</span> <span class="token string">&#39;fuse.js&#39;</span>

<span class="token keyword">const</span> fuse <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Fuse</span><span class="token punctuation">(</span>yourData<span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">keys</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;name&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;description&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token literal-property property">threshold</span><span class="token operator">:</span> <span class="token number">0.4</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token keyword">const</span> results <span class="token operator">=</span> fuse<span class="token punctuation">.</span><span class="token function">search</span><span class="token punctuation">(</span><span class="token string">&#39;query&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,37);function g(v,b){const i=t("PublishDate"),r=t("ArchitectureDiagram"),e=t("RouterLink");return l(),u("div",null,[k,n(i,{date:"2026-04-04"}),m,n(r),h,a("p",null,[s("See "),n(e,{to:"/articles/getting-started.html"},{default:o(()=>[s("Getting Started")]),_:1}),s(" for installation options (CDN, ES modules, CommonJS) and "),n(e,{to:"/articles/fuzzy-search.html"},{default:o(()=>[s("Fuzzy Search")]),_:1}),s(" to understand how scoring and thresholds work.")]),a("p",null,[s("For large datasets that benefit from parallel search, see "),n(e,{to:"/articles/web-workers.html"},{default:o(()=>[s("Web Workers")]),_:1}),s(".")])])}const f=c(d,[["render",g],["__file","vs-semantic-search.html.vue"]]);export{f as default};
